     6→use std::collections::HashMap;
     7→
     8→/// Information about a single block in a multiblock dataset
     9→#[derive(Debug, Clone, Serialize, Deserialize)]
    10→pub struct BlockInfo {
    11→    /// Name/identifier for the block
    12→    pub name: String,
    13→    /// Starting column index in the concatenated matrix
    14→    pub start_col: usize,
    15→    /// Number of columns in this block
    16→    pub n_cols: usize,
    17→    /// Optional weight for this block in consensus analysis
    18→    pub weight: f64,
    19→    /// Optional metadata about the block
    20→    pub metadata: Option<HashMap<String, String>>,
    21→}
    22→
    23→impl BlockInfo {
    24→    /// Create a new block info
    25→    pub fn new(name: String, start_col: usize, n_cols: usize) -> Self {
    26→        Self {
    27→            name,
    28→            start_col,
    29→            n_cols,
    30→            weight: 1.0,
    31→            metadata: None,
    32→        }
    33→    }
    34→    
    35→    /// Set the weight for this block
    36→    pub fn with_weight(mut self, weight: f64) -> Self {
    37→        self.weight = weight;
    38→        self
    39→    }
    40→    
    41→    /// Add metadata to the block
    42→    pub fn with_metadata(mut self, key: String, value: String) -> Self {
    43→        if self.metadata.is_none() {
    44→            self.metadata = Some(HashMap::new());
    45→        }
    46→        if let Some(ref mut metadata) = self.metadata {
    47→            metadata.insert(key, value);
    48→        }
    49→        self
    50→    }
    51→    
    52→    /// Get the ending column index (exclusive)
    53→    pub fn end_col(&self) -> usize {
    54→        self.start_col + self.n_cols
    55→    }
    56→    
    57→    /// Check if a column index is within this block
    58→    pub fn contains_column(&self, col_idx: usize) -> bool {
    59→        col_idx >= self.start_col && col_idx < self.end_col()
    60→    }
    61→}
    62→
    63→/// A single block of data with its associated information
    64→#[derive(Debug, Clone)]
    65→pub struct Block {
    66→    /// Block metadata
    67→    pub info: BlockInfo,
    68→    /// The data matrix for this block
    69→    pub data: Matrix,
    70→}
    71→
    72→impl Block {
    73→    /// Create a new block
    74→    pub fn new(info: BlockInfo, data: Matrix) -> Result<Self, MultivariousError> {
    75→        if data.ncols() != info.n_cols {
    76→            return Err(MultivariousError::DimensionMismatch {
    77→                expected: format!("{} columns", info.n_cols),
    78→                actual: format!("{} columns", data.ncols()),
    79→            });
    80→        }
    81→        
    82→        Ok(Self { info, data })
    83→    }
    84→    
    85→    /// Get the number of rows
    86→    pub fn n_rows(&self) -> usize {
    87→        self.data.nrows()
    88→    }
    89→    
    90→    /// Get the number of columns
    91→    pub fn n_cols(&self) -> usize {
    92→        self.data.ncols()
    93→    }
    94→    
    95→    /// Get a reference to the data
    96→    pub fn data(&self) -> &Matrix {
    97→        &self.data
    98→    }
    99→    
   100→    /// Get a mutable reference to the data
   101→    pub fn data_mut(&mut self) -> &mut Matrix {
   102→        &mut self.data
   103→    }
   104→}
   105→
   106→/// Indices for accessing blocks in a concatenated matrix
   107→#[derive(Debug, Clone)]
   108→pub struct BlockIndices {
   109→    /// Mapping from block name to column range
   110→    indices: HashMap<String, (usize, usize)>,
   111→    /// Total number of columns across all blocks
   112→    total_cols: usize,
   113→    /// Order of blocks
   114→    block_order: Vec<String>,
   115→}
   116→
   117→impl BlockIndices {
   118→    /// Create new block indices from block information
   119→    pub fn from_blocks(blocks: &[BlockInfo]) -> Self {
   120→        let mut indices = HashMap::new();
   121→        let mut block_order = Vec::new();
   122→        let mut total_cols = 0;
   123→        
   124→        for block in blocks {
   125→            indices.insert(
   126→                block.name.clone(),
   127→                (block.start_col, block.end_col())
   128→            );
   129→            block_order.push(block.name.clone());
   130→            total_cols = total_cols.max(block.end_col());
   131→        }
   132→        
   133→        Self {
   134→            indices,
   135→            total_cols,
   136→            block_order,
   137→        }
   138→    }
   139→    
   140→    /// Get the column range for a block by name
   141→    pub fn get_range(&self, block_name: &str) -> Option<(usize, usize)> {
   142→        self.indices.get(block_name).copied()
   143→    }
   144→    
   145→    /// Get all block names in order
   146→    pub fn block_names(&self) -> &[String] {
   147→        &self.block_order
   148→    }
   149→    
   150→    /// Get the total number of columns
   151→    pub fn total_columns(&self) -> usize {
   152→        self.total_cols
   153→    }
   154→    
   155→    /// Check if a block exists
   156→    pub fn contains_block(&self, block_name: &str) -> bool {
   157→        self.indices.contains_key(block_name)
   158→    }
   159→    
   160→    /// Get the number of blocks
   161→    pub fn n_blocks(&self) -> usize {
   162→        self.indices.len()
   163→    }
   164→}
   165→
   166→/// A multiblock dataset containing multiple blocks of data
   167→#[derive(Debug, Clone)]
   168→pub struct BlockDataset {
   169→    /// Individual blocks
   170→    blocks: Vec<Block>,
   171→    /// Block indices for the concatenated representation
   172→    indices: BlockIndices,
   173→    /// Number of observations (rows)
   174→    n_obs: usize,
   175→}
   176→
   177→impl BlockDataset {
   178→    /// Create a new block dataset from individual blocks
   179→    pub fn new(blocks: Vec<Block>) -> Result<Self, MultivariousError> {
   180→        if blocks.is_empty() {
   181→            return Err(MultivariousError::InvalidParameter {
   182→                name: "blocks".to_string(),
   183→                value: "empty vector".to_string(),
   184→                reason: "At least one block is required".to_string(),
   185→            });
   186→        }
   187→        
   188→        // Check that all blocks have the same number of rows
   189→        let n_obs = blocks[0].n_rows();
   190→        for block in blocks.iter().skip(1) {
   191→            if block.n_rows() != n_obs {
   192→                return Err(MultivariousError::DimensionMismatch {
   193→                    expected: format!("{} rows (from first block)", n_obs),
   194→                    actual: format!("{} rows in block '{}'", block.n_rows(), block.info.name),
   195→                });
   196→            }
   197→        }
   198→        
   199→        // Update block info with correct column indices
   200→        let mut current_col = 0;
   201→        let mut updated_blocks = Vec::new();
   202→        
   203→        for mut block in blocks {
   204→            block.info.start_col = current_col;
   205→            current_col += block.info.n_cols;
   206→            updated_blocks.push(block);
   207→        }
   208→        
   209→        let block_infos: Vec<BlockInfo> = updated_blocks.iter()
   210→            .map(|b| b.info.clone())
   211→            .collect();
   212→        let indices = BlockIndices::from_blocks(&block_infos);
   213→        
   214→        Ok(Self {
   215→            blocks: updated_blocks,
   216→            indices,
   217→            n_obs,
   218→        })
   219→    }
   220→    
   221→    /// Create a block dataset from a concatenated matrix and block information
   222→    pub fn from_concatenated(data: &Matrix, block_infos: Vec<BlockInfo>) -> Result<Self, MultivariousError> {
   223→        let mut blocks = Vec::new();
   224→        
   225→        for info in block_infos {
   226→            if info.end_col() > data.ncols() {
   227→                return Err(MultivariousError::InvalidParameter {
   228→                    name: "block_infos".to_string(),
   229→                    value: format!("{}-{}", info.start_col, info.end_col()),
   230→                    reason: format!("Block '{}' extends beyond matrix columns", info.name),
   231→                });
   232→            }
   233→            
   234→            let block_data = data.slice(ndarray::s![.., info.start_col..info.end_col()]).to_owned();
   235→            blocks.push(Block::new(info, block_data)?);
   236→        }
   237→        
   238→        Self::new(blocks)
   239→    }
   240→    
   241→    /// Get the number of blocks
   242→    pub fn n_blocks(&self) -> usize {
   243→        self.blocks.len()
   244→    }
   245→    
   246→    /// Get the number of observations
   247→    pub fn n_obs(&self) -> usize {
   248→        self.n_obs
   249→    }
   250→    
   251→    /// Get the total number of columns across all blocks
   252→    pub fn n_cols(&self) -> usize {
   253→        self.indices.total_columns()
   254→    }
   255→    
   256→    /// Get a reference to a block by index
   257→    pub fn get_block(&self, index: usize) -> Option<&Block> {
   258→        self.blocks.get(index)
   259→    }
   260→    
   261→    /// Get a reference to a block by name
   262→    pub fn get_block_by_name(&self, name: &str) -> Option<&Block> {
   263→        self.blocks.iter().find(|b| b.info.name == name)
   264→    }
   265→    
   266→    /// Get a mutable reference to a block by index
   267→    pub fn get_block_mut(&mut self, index: usize) -> Option<&mut Block> {
   268→        self.blocks.get_mut(index)
   269→    }
   270→    
   271→    /// Get a mutable reference to a block by name
   272→    pub fn get_block_by_name_mut(&mut self, name: &str) -> Option<&mut Block> {
   273→        self.blocks.iter_mut().find(|b| b.info.name == name)
   274→    }
   275→    
   276→    /// Get all blocks
   277→    pub fn blocks(&self) -> &[Block] {
   278→        &self.blocks
   279→    }
   280→    
   281→    /// Get mutable access to all blocks
   282→    pub fn blocks_mut(&mut self) -> &mut Vec<Block> {
   283→        &mut self.blocks
   284→    }
   285→    
   286→    /// Get the block indices
   287→    pub fn indices(&self) -> &BlockIndices {
   288→        &self.indices
   289→    }
   290→    
   291→    /// Concatenate all blocks into a single matrix
   292→    pub fn to_concatenated(&self) -> Matrix {
   293→        let mut result = Matrix::zeros((self.n_obs, self.n_cols()));
   294→        
   295→        for block in &self.blocks {
   296→            let start = block.info.start_col;
   297→            let end = block.info.end_col();
   298→            result.slice_mut(ndarray::s![.., start..end]).assign(&block.data);
   299→        }
   300→        
   301→        result
   302→    }
   303→    
   304→    /// Create an iterator over blocks
   305→    pub fn iter(&self) -> impl Iterator<Item = &Block> {
   306→        self.blocks.iter()
   307→    }
   308→    
   309→    /// Create a mutable iterator over blocks
   310→    pub fn iter_mut(&mut self) -> impl Iterator<Item = &mut Block> {
   311→        self.blocks.iter_mut()
   312→    }
   313→    
   314→    /// Extract a subset of blocks by name
   315→    pub fn subset(&self, block_names: &[String]) -> Result<Self, MultivariousError> {
   316→        let mut subset_blocks = Vec::new();
   317→        
   318→        for name in block_names {
   319→            if let Some(block) = self.get_block_by_name(name) {
   320→                subset_blocks.push(block.clone());
   321→            } else {
   322→                return Err(MultivariousError::InvalidParameter {
   323→                    name: "block_names".to_string(),
   324→                    value: name.clone(),
   325→                    reason: format!("Block '{}' not found", name),
   326→                });
   327→            }
   328→        }
   329→        
   330→        Self::new(subset_blocks)
   331→    }
   332→    
   333→    /// Apply a function to each block
   334→    pub fn map_blocks<F>(&self, f: F) -> Result<Self, MultivariousError>
   335→    where
   336→        F: Fn(&Block) -> Result<Matrix, MultivariousError>,
   337→    {
   338→        let mut new_blocks = Vec::new();
   339→        
   340→        for block in &self.blocks {
   341→            let new_data = f(block)?;
   342→            let new_block = Block::new(block.info.clone(), new_data)?;
   343→            new_blocks.push(new_block);
   344→        }
   345→        
   346→        Self::new(new_blocks)
   347→    }
   348→}
