   170→/// Support for block-wise preprocessing in multiblock analysis
   171→#[derive(Debug)]
   172→pub struct BlockwisePreprocessor {
   173→    /// Preprocessors for each block, indexed by block name
   174→    block_preprocessors: HashMap<String, Box<dyn Preprocessor>>,
   175→    /// Block sizes (number of columns per block)
   176→    block_sizes: HashMap<String, usize>,
   177→    /// Order of blocks
   178→    block_order: Vec<String>,
   179→}
   180→
   181→impl BlockwisePreprocessor {
   182→    /// Create a new blockwise preprocessor
   183→    pub fn new() -> Self {
   184→        Self {
   185→            block_preprocessors: HashMap::new(),
   186→            block_sizes: HashMap::new(),
   187→            block_order: Vec::new(),
   188→        }
   189→    }
   190→    
   191→    /// Add a preprocessor for a specific block
   192→    pub fn add_block(
   193→        mut self, 
   194→        name: String, 
   195→        preprocessor: Box<dyn Preprocessor>,
   196→        n_columns: usize
   197→    ) -> Self {
   198→        self.block_preprocessors.insert(name.clone(), preprocessor);
   199→        self.block_sizes.insert(name.clone(), n_columns);
   200→        self.block_order.push(name);
   201→        self
   202→    }
   203→    
   204→    /// Get the total number of columns across all blocks
   205→    pub fn total_columns(&self) -> usize {
   206→        self.block_sizes.values().sum()
   207→    }
   208→    
   209→    /// Split a matrix into blocks based on configured sizes
   210→    fn split_into_blocks(&self, data: &Matrix) -> Result<HashMap<String, Matrix>, MultivariousError> {
   211→        if data.ncols() != self.total_columns() {
   212→            return Err(MultivariousError::DimensionMismatch {
   213→                expected: self.total_columns().to_string(),
   214→                actual: data.ncols().to_string(),
   215→            });
   216→        }
   217→        
   218→        let mut blocks = HashMap::new();
   219→        let mut col_start = 0;
   220→        
   221→        for block_name in &self.block_order {
   222→            let n_cols = self.block_sizes[block_name];
   223→            let block_data = data.slice(ndarray::s![.., col_start..col_start + n_cols]).to_owned();
   224→            blocks.insert(block_name.clone(), block_data);
   225→            col_start += n_cols;
   226→        }
   227→        
   228→        Ok(blocks)
   229→    }
   230→    
   231→    /// Concatenate blocks back into a single matrix
   232→    fn concatenate_blocks(&self, blocks: HashMap<String, Matrix>) -> Result<Matrix, MultivariousError> {
   233→        let mut columns = Vec::new();
   234→        
   235→        for block_name in &self.block_order {
   236→            let block = blocks.get(block_name)
   237→                .ok_or_else(|| MultivariousError::PreprocessingError(
   238→                    format!("Missing block: {}", block_name)
   239→                ))?;
   240→            
   241→            for col in block.axis_iter(ndarray::Axis(1)) {
   242→                columns.push(col.to_owned());
   243→            }
   244→        }
   245→        
   246→        if columns.is_empty() {
   247→            return Err(MultivariousError::PreprocessingError(
   248→                "No columns to concatenate".to_string()
   249→            ));
   250→        }
   251→        
   252→        let n_rows = columns[0].len();
   253→        let n_cols = columns.len();
   254→        let mut result = Matrix::zeros((n_rows, n_cols));
   255→        
   256→        for (col_idx, col) in columns.iter().enumerate() {
   257→            result.column_mut(col_idx).assign(col);
   258→        }
   259→        
   260→        Ok(result)
   261→    }
   262→}
   263→
   264→impl Default for BlockwisePreprocessor {
   265→    fn default() -> Self {
   266→        Self::new()
   267→    }
   268→}
   269→
   270→impl Clone for BlockwisePreprocessor {
   271→    fn clone(&self) -> Self {
   272→        Self {
   273→            block_preprocessors: self.block_preprocessors.iter()
   274→                .map(|(k, v)| (k.clone(), v.clone_box()))
   275→                .collect(),
   276→            block_sizes: self.block_sizes.clone(),
   277→            block_order: self.block_order.clone(),
   278→        }
   279→    }
   280→}
