   287→    fn fit(&mut self, data: &Matrix) -> Result<(), MultivariousError> {
   288→        let blocks = self.split_into_blocks(data)?;
   289→        
   290→        for (block_name, block_data) in blocks {
   291→            if let Some(preprocessor) = self.block_preprocessors.get_mut(&block_name) {
   292→                preprocessor.fit(&block_data)?;
   293→            }
   294→        }
   295→        
   296→        Ok(())
   297→    }
   298→    
   299→    fn transform(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
   300→        let blocks = self.split_into_blocks(data)?;
   301→        let mut transformed_blocks = HashMap::new();
   302→        
   303→        for (block_name, block_data) in blocks {
   304→            if let Some(preprocessor) = self.block_preprocessors.get(&block_name) {
   305→                let transformed = preprocessor.transform(&block_data)?;
   306→                transformed_blocks.insert(block_name, transformed);
   307→            }
   308→        }
   309→        
   310→        self.concatenate_blocks(transformed_blocks)
   311→    }
   312→    
   313→    fn inverse_transform(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
   314→        let blocks = self.split_into_blocks(data)?;
   315→        let mut inverse_blocks = HashMap::new();
   316→        
   317→        for (block_name, block_data) in blocks {
   318→            if let Some(preprocessor) = self.block_preprocessors.get(&block_name) {
   319→                let inverse = preprocessor.inverse_transform(&block_data)?;
   320→                inverse_blocks.insert(block_name, inverse);
   321→            }
   322→        }
   323→        
   324→        self.concatenate_blocks(inverse_blocks)
   325→    }
   326→    
   327→    fn is_fitted(&self) -> bool {
   328→        self.block_preprocessors.values().all(|p| p.is_fitted())
   329→    }
   330→    
   331→    fn name(&self) -> &str {
   332→        "BlockwisePreprocessor"
   333→    }
   334→}
