//! Multiblock projector implementations

use crate::common_types::{Matrix, Vector};
use crate::errors::MultivariousError;
use crate::projector::traits::{Project, Reconstruct, PartialProject};
use crate::projector::bi_projector::BiProjector;
use crate::preprocessing::traits::Preprocessor;
use crate::multiblock::block::{Block, BlockDataset, BlockIndices};
use std::collections::HashMap;
use serde::{Serialize, Deserialize};

/// Trait for multiblock projection operations
pub trait MultiblockProject: Project {
    /// Project a single block of data
    fn project_block(&self, block_name: &str, data: &Matrix) -> Result<Matrix, MultivariousError>;

    /// Project all blocks and return results indexed by block name
    fn project_blocks(&self, dataset: &BlockDataset) -> Result<HashMap<String, Matrix>, MultivariousError>;

    /// Get block-specific projector if available
    fn get_block_projector(&self, block_name: &str) -> Option<&dyn Project>;

    /// Get the number of components for a specific block
    fn n_components_block(&self, block_name: &str) -> Option<usize>;

    /// Get block names in order
    fn block_names(&self) -> Vec<String>;

    /// Get block weights used in projection
    fn block_weights(&self) -> HashMap<String, f64>;
}

/// Configuration for multiblock projectors
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct MultiblockConfig {
    /// Whether to use block-specific preprocessing
    pub block_preprocessing: bool,
    /// Whether to normalize block weights
    pub normalize_weights: bool,
    /// Method for combining block projections
    pub combination_method: CombinationMethod,
    /// Optional regularization parameter
    pub regularization: Option<f64>,
}

impl Default for MultiblockConfig {
    fn default() -> Self {
        Self {
            block_preprocessing: true,
            normalize_weights: true,
            combination_method: CombinationMethod::Weighted,
            regularization: None,
        }
    }
}

/// Method for combining block projections
#[derive(Debug, Clone, Copy, Serialize, Deserialize, PartialEq)]
pub enum CombinationMethod {
    /// Simple weighted average
    Weighted,
    /// Consensus-based combination
    Consensus,
    /// Sequential deflation
    Sequential,
    /// Simultaneous optimization
    Simultaneous,
}

/// Base multiblock projector that combines individual block projectors
#[derive(Debug, Clone)]
pub struct MultiblockProjector {
    /// Individual projectors for each block
    block_projectors: HashMap<String, Box<dyn Project>>,
    /// Block weights
    block_weights: HashMap<String, f64>,
    /// Block indices for concatenated representation
    block_indices: BlockIndices,
    /// Optional block-specific preprocessing
    block_preprocessors: Option<HashMap<String, Box<dyn Preprocessor>>>,
    /// Configuration
    config: MultiblockConfig,
    /// Whether the projector has been fitted
    is_fitted: bool,
    /// Total number of components across all blocks
    total_components: usize,
}

impl MultiblockProjector {
    /// Create a new multiblock projector
    pub fn new(block_indices: BlockIndices) -> Self {
        let block_names = block_indices.block_names();
        let mut block_weights = HashMap::new();

        // Initialize with equal weights
        for name in block_names {
            block_weights.insert(name.clone(), 1.0);
        }

        Self {
            block_projectors: HashMap::new(),
            block_weights,
            block_indices,
            block_preprocessors: None,
            config: MultiblockConfig::default(),
            is_fitted: false,
            total_components: 0,
        }
    }

    /// Create with specific configuration
    pub fn with_config(block_indices: BlockIndices, config: MultiblockConfig) -> Self {
        let mut projector = Self::new(block_indices);
        projector.config = config;
        projector
    }

    /// Set projector for a specific block
    pub fn set_block_projector(&mut self, block_name: String, projector: Box<dyn Project>) -> Result<(), MultivariousError> {
        if !self.block_indices.contains_block(&block_name) {
            return Err(MultivariousError::InvalidParameter {
                name: "block_name".to_string(),
                value: block_name,
                reason: "Block not found in indices".to_string(),
            });
        }

        self.block_projectors.insert(block_name, projector);
        self.update_total_components();
        Ok(())
    }

    /// Set weight for a specific block
    pub fn set_block_weight(&mut self, block_name: &str, weight: f64) -> Result<(), MultivariousError> {
        if !self.block_indices.contains_block(block_name) {
            return Err(MultivariousError::InvalidParameter {
                name: "block_name".to_string(),
                value: block_name.to_string(),
                reason: "Block not found in indices".to_string(),
            });
        }

        if weight < 0.0 {
            return Err(MultivariousError::InvalidParameter {
                name: "weight".to_string(),
                value: weight.to_string(),
                reason: "Weight must be non-negative".to_string(),
            });
        }

        self.block_weights.insert(block_name.to_string(), weight);
        Ok(())
    }

    /// Set preprocessor for a specific block
    pub fn set_block_preprocessor(&mut self, block_name: String, preprocessor: Box<dyn Preprocessor>) -> Result<(), MultivariousError> {
        if !self.block_indices.contains_block(&block_name) {
            return Err(MultivariousError::InvalidParameter {
                name: "block_name".to_string(),
                value: block_name,
                reason: "Block not found in indices".to_string(),
            });
        }

        if self.block_preprocessors.is_none() {
            self.block_preprocessors = Some(HashMap::new());
        }

        if let Some(ref mut preprocessors) = self.block_preprocessors {
            preprocessors.insert(block_name, preprocessor);
        }

        Ok(())
    }

    /// Update total component count
    fn update_total_components(&mut self) {
        self.total_components = self.block_projectors.values()
            .map(|p| p.n_components())
            .sum();
    }

    /// Normalize block weights to sum to 1
    fn normalize_weights(&mut self) {
        if self.config.normalize_weights {
            let sum: f64 = self.block_weights.values().sum();
            if sum > 0.0 {
                for weight in self.block_weights.values_mut() {
