mod tests {
    use super::*;
    use crate::projector::base::BaseProjector;
    use ndarray::array;

    /// Create a simple test projector
    fn create_test_projector(n_components: usize, n_features: usize) -> BaseProjector {
        // Create a simple projection matrix (identity-like)
        let mut projection = Matrix::zeros((n_features, n_components));
        for i in 0..n_components.min(n_features) {
            projection[[i, i]] = 1.0;
        }
        BaseProjector::new(projection)
    }

    #[test]
    fn test_multiblock_projector_creation() {
        let block_infos = vec![
            BlockInfo::new("block1".to_string(), 0, 3),
            BlockInfo::new("block2".to_string(), 3, 2),
        ];
        let indices = BlockIndices::from_blocks(&block_infos);

        let projector = MultiblockProjector::new(indices.clone());

        assert_eq!(projector.block_names(), vec!["block1", "block2"]);
        assert_eq!(projector.n_features(), 5);
        assert_eq!(projector.n_components(), 0); // No block projectors set yet
        assert!(!projector.is_fitted());
    }

    #[test]
    fn test_set_block_projector() {
        let block_infos = vec![
            BlockInfo::new("block1".to_string(), 0, 3),
            BlockInfo::new("block2".to_string(), 3, 2),
        ];
        let indices = BlockIndices::from_blocks(&block_infos);

        let mut multiblock = MultiblockProjector::new(indices);

        // Set projectors for each block
        let proj1 = create_test_projector(2, 3);
        let proj2 = create_test_projector(1, 2);

        multiblock.set_block_projector("block1".to_string(), Box::new(proj1)).unwrap();
        multiblock.set_block_projector("block2".to_string(), Box::new(proj2)).unwrap();

        assert_eq!(multiblock.n_components(), 3); // 2 + 1 components
        assert_eq!(multiblock.n_components_block("block1"), Some(2));
        assert_eq!(multiblock.n_components_block("block2"), Some(1));
    }

    #[test]
    fn test_block_weights() {
        let block_infos = vec![
            BlockInfo::new("block1".to_string(), 0, 3),
            BlockInfo::new("block2".to_string(), 3, 2),
        ];
        let indices = BlockIndices::from_blocks(&block_infos);

        let mut multiblock = MultiblockProjector::new(indices);

        // Initially all weights are 1.0
        let weights = multiblock.block_weights();
        assert_eq!(weights.get("block1"), Some(&1.0));
        assert_eq!(weights.get("block2"), Some(&1.0));

        // Set custom weights
        multiblock.set_block_weight("block1", 2.0).unwrap();
        multiblock.set_block_weight("block2", 0.5).unwrap();

        let weights = multiblock.block_weights();
        assert_eq!(weights.get("block1"), Some(&2.0));
        assert_eq!(weights.get("block2"), Some(&0.5));
    }

    #[test]
    fn test_weight_normalization() {
        let block_infos = vec![
            BlockInfo::new("block1".to_string(), 0, 3),
            BlockInfo::new("block2".to_string(), 3, 2),
        ];
        let indices = BlockIndices::from_blocks(&block_infos);

        let mut config = MultiblockConfig::default();
        config.normalize_weights = true;

        let mut multiblock = MultiblockProjector::with_config(indices, config);

        // Set weights that don't sum to 1
        multiblock.set_block_weight("block1", 3.0).unwrap();
        multiblock.set_block_weight("block2", 1.0).unwrap();

        // Normalize weights
        multiblock.normalize_weights();

        let weights = multiblock.block_weights();
        assert!((weights.get("block1").unwrap() - 0.75).abs() < 1e-10);
        assert!((weights.get("block2").unwrap() - 0.25).abs() < 1e-10);
    }

    #[test]
    fn test_invalid_block_operations() {
        let block_infos = vec![
            BlockInfo::new("block1".to_string(), 0, 3),
