    fn test_block_dataset_projection() {
        let blocks = vec![
            Block::new(
                BlockInfo::new("A".to_string(), 0, 2),
                array![[1.0, 2.0], [3.0, 4.0]]
            ).unwrap(),
            Block::new(
                BlockInfo::new("B".to_string(), 2, 2),
                array![[5.0, 6.0], [7.0, 8.0]]
            ).unwrap(),
        ];
        let dataset = BlockDataset::new(blocks).unwrap();
        let indices = dataset.indices().clone();

        let mut multiblock = MultiblockProjector::new(indices);

        // Set projectors
        let proj_a = create_test_projector(1, 2);
        let proj_b = create_test_projector(1, 2);

        multiblock.set_block_projector("A".to_string(), Box::new(proj_a)).unwrap();
        multiblock.set_block_projector("B".to_string(), Box::new(proj_b)).unwrap();

        // Project blocks individually
        let block_projections = multiblock.project_blocks(&dataset).unwrap();

        assert_eq!(block_projections.len(), 2);
        assert!(block_projections.contains_key("A"));
        assert!(block_projections.contains_key("B"));

        // Check individual projections
        let proj_a = block_projections.get("A").unwrap();
        assert_eq!(proj_a.shape(), &[2, 1]);
        assert_eq!(proj_a[[0, 0]], 1.0);

        let proj_b = block_projections.get("B").unwrap();
        assert_eq!(proj_b.shape(), &[2, 1]);
        assert_eq!(proj_b[[0, 0]], 5.0);
    }

    #[test]
    fn test_combination_methods() {
        let block_infos = vec![
            BlockInfo::new("block1".to_string(), 0, 2),
            BlockInfo::new("block2".to_string(), 2, 2),
        ];
        let indices = BlockIndices::from_blocks(&block_infos);

